mapper.sql:
from aiw_ai_prompt_template p
where 1 = 1

    and p.prompt_code = #{criteria.promptCode}


    and p.scenario = #{criteria.scenario}


    and p.status = #{criteria.status}

mapper.select:
select * from aiw_ai_prompt_template
where prompt_code = #{promptCode}
  and prompt_version = #{promptVersion}

select * from aiw_ai_prompt_variable
where prompt_biz_id = #{promptBizId}
order by variable_name asc

select * from aiw_ai_prompt_output_schema
where prompt_biz_id = #{promptBizId}
order by schema_version desc

select p.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
